import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // Quote — base premiums for single items
  it.todo("empty item list yields premium of 5 G (only processing fee)");
  it.todo("quote for a single plain sword yields 105 G (100 base + 5 fee)");
  it.todo("quote for a single plain amulet yields 65 G (60 base + 5 fee)");
  it.todo("quote for a single plain staff yields 85 G (80 base + 5 fee)");
  it.todo("quote for a single plain potion yields 45 G (40 base + 5 fee)");

  // Quote — components and building block
  it.todo("quote for a single rune yields 30 G (25 base + 5 fee)");
  it.todo("quote for 2 runes yields 55 G (50 base + 5 fee, no block)");
  it.todo("quote for 3 runes yields 65 G (60 block base + 5 fee)");
  it.todo("quote for 4 runes yields 105 G (100 base + 5 fee, no block)");
  it.todo("quote for 2 runes + 1 moonstone yields 80 G (75 base + 5 fee, different types)");
  it.todo("quote for 3 runes + 3 moonstones yields 125 G (two blocks of 60 + 5 fee)");

  // Quote — premium modifiers (item-specific)
  it.todo("cursed sword adds 50% surcharge on that item's base premium");
  it.todo("highly enchanted item (enchantment ≥ 5) adds 30% surcharge on its base premium");
  it.todo("sword with enchantment exactly 5 triggers high-enchantment surcharge");
  it.todo("sword with enchantment 4 does not trigger high-enchantment surcharge");
  it.todo("cursed and highly enchanted item gets both surcharges");

  // Quote — premium modifiers (policy-wide)
  it.todo("long-standing customer (≥ 2 years) receives 20% loyalty discount on policy base premium");
  it.todo("customer with exactly 2 years gets loyalty discount");
  it.todo("first insurance adds 10% surcharge per item");
  it.todo("follow-up contract (after first) gets 15% discount on policy base premium");

  // Quote — rounding
  it.todo("premium rounds up to whole G in MHPCO's favor");

  // Integration — newcomer with cursed sword: 165 G
  it.todo("newcomer with cursed sword yields 165 G");

  // Integration — long-standing customer's second contract: 160 G
  it.todo("long-standing customer second contract with cursed enchanted sword yields 160 G");

  // Claim — basic
  it.todo("standard sword claim of 500 G yields payout 400 G (full minus 100 deductible)");
  it.todo("rune damage of 200 G yields payout 100 G (full minus 100 deductible)");
  it.todo("payout rounds down in MHPCO's favor");

  // Claim — special clauses
  it.todo("high enchantment (≥ 8) reimburses 50% of damage, then deductible");
  it.todo("dragon material item is fully reimbursed");
  it.todo("dragon material with high enchantment: 50% rule wins, then deductible");

  // Claim — multiple damages
  it.todo("multiple damages each get their own deductible");

  // Claim — cap
  it.todo("payout capped at twice the insurance sum");
  it.todo("successive claims exhaust remaining cap");

  // Multi-item policy
  it.todo("policy with cursed sword and plain amulet yields 215 G");
  it.todo("policy with two swords has insurance sum 2000 G, cap 4000 G");

  // Errors
  it.todo("unknown item type causes CLI to exit non-zero");
  it.todo("claim with item not in policy causes non-zero exit");
  it.todo("claim with negative damage amount causes non-zero exit");
  it.todo("more damage entries of a type than insured items causes non-zero exit");
});

