export interface Customer {
  yearsWithMHPCO: number;
}

export interface Item {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
}

export interface QuoteStep {
  op: "quote";
  items: Item[];
}

export interface Damage {
  itemType: string;
  amount: number;
}

export interface ClaimStep {
  op: "claim";
  policy: number;
  incident: {
    cause?: string;
    damages: Damage[];
  };
}

export type Step = QuoteStep | ClaimStep;

export interface Scenario {
  customer: Customer;
  steps: Step[];
}

export interface QuoteResult {
  premium: number;
}

export interface ClaimResult {
  payout: number;
  remainingCap: number;
}

export type StepResult = QuoteResult | ClaimResult;

export interface ScenarioResult {
  results: StepResult[];
}

const PROCESSING_FEE = 5;

const ITEM_BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const basePremiumFor = (item: Item): number => ITEM_BASE_PREMIUM[item.type];

const COMPONENT_BLOCK_PREMIUM = 60;

const sumBasePremiums = (items: Item[]): number =>
  items.reduce((sum, item) => sum + basePremiumFor(item), 0);

const isRune = (item: Item): boolean => item.type === "rune";

const itemsBaseTotal = (items: Item[]): number => {
  const runeCount = items.filter(isRune).length;
  if (runeCount === 3) {
    const nonRunes = items.filter((i) => !isRune(i));
    return COMPONENT_BLOCK_PREMIUM + sumBasePremiums(nonRunes);
  }
  return sumBasePremiums(items);
};

const quote = ({ items }: QuoteStep): QuoteResult => ({
  premium: itemsBaseTotal(items) + PROCESSING_FEE,
});

export const runScenario = (scenario: Scenario): ScenarioResult => ({
  results: scenario.steps.map((step) =>
    step.op === "quote" ? quote(step) : { payout: 0, remainingCap: 0 },
  ),
});

