export interface Customer {
  yearsWithMHPCO: number;
}

export interface Item {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
}

export interface QuoteStep {
  op: "quote";
  items: Item[];
}

export interface Damage {
  itemType: string;
  amount: number;
}

export interface ClaimStep {
  op: "claim";
  policy: number;
  incident: {
    cause?: string;
    damages: Damage[];
  };
}

export type Step = QuoteStep | ClaimStep;

export interface Scenario {
  customer: Customer;
  steps: Step[];
}

export interface QuoteResult {
  premium: number;
}

export interface ClaimResult {
  payout: number;
  remainingCap: number;
}

export type StepResult = QuoteResult | ClaimResult;

export interface ScenarioResult {
  results: StepResult[];
}

const PROCESSING_FEE = 5;

const ITEM_BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const basePremiumFor = (item: Item): number => ITEM_BASE_PREMIUM[item.type];

const COMPONENT_BLOCK_PREMIUM = 60;

const sumBasePremiums = (items: Item[]): number =>
  items.reduce((sum, item) => sum + basePremiumFor(item), 0);

const COMPONENT_TYPES = ["rune", "moonstone"];

const isComponent = (item: Item): boolean => COMPONENT_TYPES.includes(item.type);

const componentGroupTotal = (group: Item[]): number =>
  group.length === 3 ? COMPONENT_BLOCK_PREMIUM : sumBasePremiums(group);

const componentsTotal = (items: Item[]): number =>
  COMPONENT_TYPES.reduce(
    (sum, type) => sum + componentGroupTotal(items.filter((i) => i.type === type)),
    0,
  );

const itemsBaseTotal = (items: Item[]): number =>
  sumBasePremiums(items.filter((i) => !isComponent(i))) + componentsTotal(items);

const CURSE_SURCHARGE_RATE = 0.5;
const HIGH_ENCHANTMENT_THRESHOLD = 5;
const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;

const ITEM_SURCHARGE_RATES: ReadonlyArray<(item: Item) => number> = [
  (item) => (item.cursed ? CURSE_SURCHARGE_RATE : 0),
  (item) => ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD ? HIGH_ENCHANTMENT_SURCHARGE_RATE : 0),
];

const itemSurchargeRate = (item: Item): number =>
  ITEM_SURCHARGE_RATES.reduce((sum, rate) => sum + rate(item), 0);

const itemSurcharges = (items: Item[]): number =>
  items.reduce((sum, item) => sum + basePremiumFor(item) * itemSurchargeRate(item), 0);

const LOYALTY_THRESHOLD_YEARS = 2;
const LOYALTY_DISCOUNT_RATE = 0.2;

const policyDiscountRate = (customer: Customer): number =>
  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? LOYALTY_DISCOUNT_RATE : 0;

const quote = ({ items }: QuoteStep, customer: Customer): QuoteResult => {
  const policyBase = itemsBaseTotal(items);
  const discount = policyBase * policyDiscountRate(customer);
  return {
    premium: policyBase - discount + itemSurcharges(items) + PROCESSING_FEE,
  };
};

export const runScenario = (scenario: Scenario): ScenarioResult => ({
  results: scenario.steps.map((step) =>
    step.op === "quote" ? quote(step, scenario.customer) : { payout: 0, remainingCap: 0 },
  ),
});

import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // Quote — base premiums for single items
  it("empty item list yields premium of 5 G (only processing fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [] }],
    });
    expect(result.results[0]).toEqual({ premium: 5 });
  });
  it("quote for a single plain sword yields 105 G (100 base + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 105 });
  });
  it("quote for a single plain amulet yields 65 G (60 base + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "amulet", material: "silver", enchantment: 0, cursed: false }],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 65 });
  });
  it("quote for a single plain staff yields 85 G (80 base + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "staff", material: "wood", enchantment: 0, cursed: false }],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 85 });
  });
  it("quote for a single plain potion yields 45 G (40 base + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "potion", material: "glass", enchantment: 0, cursed: false }],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 45 });
  });

  // Quote — components and building block
  it("quote for a single rune yields 30 G (25 base + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }] }],
    });
    expect(result.results[0]).toEqual({ premium: 30 });
  });
  it("quote for 2 runes yields 55 G (50 base + 5 fee, no block)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }] }],
    });
    expect(result.results[0]).toEqual({ premium: 55 });
  });
  it("quote for 3 runes yields 65 G (60 block base + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 65 });
  });
  it("quote for 4 runes yields 105 G (100 base + 5 fee, no block)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 105 });
  });
  it("quote for 2 runes + 1 moonstone yields 80 G (75 base + 5 fee, different types)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "rune" }, { type: "rune" }, { type: "moonstone" }],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 80 });
  });
  it("quote for 3 runes + 3 moonstones yields 125 G (two blocks of 60 + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "rune" },
            { type: "rune" },
            { type: "rune" },
            { type: "moonstone" },
            { type: "moonstone" },
            { type: "moonstone" },
          ],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 125 });
  });

  // Quote — premium modifiers (item-specific)
  it("cursed sword adds 50% surcharge on that item's base premium", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 0, cursed: true }],
        },
