    steps: [
      {
        op: "quote",
        items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }],
      },
    ],
  });
  expect(result.results[0]).toEqual({ premium: 65 });
});
it("quote for 4 runes yields 105 G (100 base + 5 fee, no block)", () => {
  const result = runScenario({
    customer: { yearsWithMHPCO: 0 },
    steps: [
      {
        op: "quote",
        items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }],
      },
    ],
  });
  expect(result.results[0]).toEqual({ premium: 105 });
});
it("quote for 2 runes + 1 moonstone yields 80 G (75 base + 5 fee, different types)", () => {
  const result = runScenario({
    customer: { yearsWithMHPCO: 0 },
    steps: [
      {
        op: "quote",
        items: [{ type: "rune" }, { type: "rune" }, { type: "moonstone" }],
      },
    ],
  });
  expect(result.results[0]).toEqual({ premium: 80 });
});
it("quote for 3 runes + 3 moonstones yields 125 G (two blocks of 60 + 5 fee)", () => {
  const result = runScenario({
    customer: { yearsWithMHPCO: 0 },
    steps: [
      {
        op: "quote",
        items: [
          { type: "rune" },
          { type: "rune" },
          { type: "rune" },
          { type: "moonstone" },
          { type: "moonstone" },
          { type: "moonstone" },
        ],
      },
    ],
  });
  expect(result.results[0]).toEqual({ premium: 125 });
});

// Quote — premium modifiers (item-specific)
it("cursed sword adds 50% surcharge on that item's base premium", () => {
  const result = runScenario({
    customer: { yearsWithMHPCO: 0 },
    steps: [
      {
        op: "quote",
        items: [{ type: "sword", material: "steel", enchantment: 0, cursed: true }],
      },
    ],
  });
  // 100 base + 50 curse + 5 fee = 155
  expect(result.results[0]).toEqual({ premium: 155 });
});
it("highly enchanted item (enchantment ≥ 5) adds 30% surcharge on its base premium", () => {
  const result = runScenario({
    customer: { yearsWithMHPCO: 0 },
    steps: [
      {
        op: "quote",
        items: [{ type: "sword", material: "steel", enchantment: 7, cursed: false }],
      },
    ],
  });
  // 100 base + 30 surcharge + 5 fee = 135
  expect(result.results[0]).toEqual({ premium: 135 });
});
it("sword with enchantment exactly 5 triggers high-enchantment surcharge", () => {
  const result = runScenario({
    customer: { yearsWithMHPCO: 0 },
    steps: [
      {
        op: "quote",
        items: [{ type: "sword", material: "steel", enchantment: 5, cursed: false }],
      },
    ],
  });
  expect(result.results[0]).toEqual({ premium: 135 });
});
it("sword with enchantment 4 does not trigger high-enchantment surcharge", () => {
  const result = runScenario({
    customer: { yearsWithMHPCO: 0 },
    steps: [
      {
        op: "quote",
        items: [{ type: "sword", material: "steel", enchantment: 4, cursed: false }],
      },
    ],
  });
  expect(result.results[0]).toEqual({ premium: 105 });
});
it("cursed and highly enchanted item gets both surcharges", () => {
  const result = runScenario({
    customer: { yearsWithMHPCO: 0 },
    steps: [
      {
        op: "quote",
        items: [{ type: "sword", material: "steel", enchantment: 5, cursed: true }],
      },
    ],
  });
  // 100 base + 50 curse + 30 enchant + 5 fee = 185
  expect(result.results[0]).toEqual({ premium: 185 });
});

// Quote — premium modifiers (policy-wide)
