import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // Quote — base premiums for single items
  it("empty item list yields premium of 5 G (only processing fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [] }],
    });
    expect(result.results[0]).toEqual({ premium: 5 });
  });
  it("quote for a single plain sword yields 115 G (100 base + 10 first insurance + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 115 });
  });
  it("quote for a single plain amulet yields 71 G (60 base + 6 first insurance + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "amulet", material: "silver", enchantment: 0, cursed: false }],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 71 });
  });
  it("quote for a single plain staff yields 93 G (80 base + 8 first insurance + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "staff", material: "wood", enchantment: 0, cursed: false }],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 93 });
  });
  it("quote for a single plain potion yields 49 G (40 base + 4 first insurance + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "potion", material: "glass", enchantment: 0, cursed: false }],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 49 });
  });

  // Quote — components and building block
  it("quote for a single rune yields 30 G (25 base + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }] }],
    });
    expect(result.results[0]).toEqual({ premium: 30 });
  });
  it("quote for 2 runes yields 55 G (50 base + 5 fee, no block)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }] }],
    });
    expect(result.results[0]).toEqual({ premium: 55 });
  });
  it("quote for 3 runes yields 65 G (60 block base + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 65 });
  });
  it("quote for 4 runes yields 105 G (100 base + 5 fee, no block)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 105 });
  });
  it("quote for 2 runes + 1 moonstone yields 80 G (75 base + 5 fee, different types)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "rune" }, { type: "rune" }, { type: "moonstone" }],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 80 });
  });
  it("quote for 3 runes + 3 moonstones yields 125 G (two blocks of 60 + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "rune" },
            { type: "rune" },
            { type: "rune" },
            { type: "moonstone" },
            { type: "moonstone" },
            { type: "moonstone" },
          ],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 125 });
  });

  // Quote — premium modifiers (item-specific)
  it("cursed sword adds 50% surcharge on that item's base premium", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 0, cursed: true }],
        },
      ],
    });
    // 100 base + 50 curse + 5 fee = 155
    expect(result.results[0]).toEqual({ premium: 155 });
  });
  it("highly enchanted item (enchantment ≥ 5) adds 30% surcharge on its base premium", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 7, cursed: false }],
        },
      ],
    });
    // 100 base + 30 surcharge + 5 fee = 135
    expect(result.results[0]).toEqual({ premium: 135 });
  });
  it("sword with enchantment exactly 5 triggers high-enchantment surcharge", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 5, cursed: false }],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 135 });
  });
  it("sword with enchantment 4 does not trigger high-enchantment surcharge", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 4, cursed: false }],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 105 });
  });
  it("cursed and highly enchanted item gets both surcharges", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 5, cursed: true }],
        },
      ],
    });
    // 100 base + 50 curse + 30 enchant + 5 fee = 185
    expect(result.results[0]).toEqual({ premium: 185 });
  });

  // Quote — premium modifiers (policy-wide)
  it("long-standing customer (≥ 2 years) receives 20% loyalty discount on policy base premium", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 3 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }],
        },
      ],
    });
    // 100 base - 20 loyalty + 5 fee = 85
    expect(result.results[0]).toEqual({ premium: 85 });
  });
  it("customer with exactly 2 years gets loyalty discount", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 2 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }],
        },
      ],
    });
    // 100 base - 20 loyalty + 5 fee = 85
    expect(result.results[0]).toEqual({ premium: 85 });
  });
  it("first insurance adds 10% surcharge per item", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "sword", material: "steel", enchantment: 0, cursed: false },
            { type: "amulet", material: "silver", enchantment: 0, cursed: false },
          ],
        },
      ],
    });
    // 100 + 60 base + 10 + 6 first insurance + 5 fee = 181
    expect(result.results[0]).toEqual({ premium: 181 });
  });
  it.todo("follow-up contract (after first) gets 15% discount on policy base premium");

  // Quote — rounding
  it.todo("premium rounds up to whole G in MHPCO's favor");

  // Integration — newcomer with cursed sword: 165 G
  it.todo("newcomer with cursed sword yields 165 G");

  // Integration — long-standing customer's second contract: 160 G
  it.todo("long-standing customer second contract with cursed enchanted sword yields 160 G");

  // Claim — basic
  it.todo("standard sword claim of 500 G yields payout 400 G (full minus 100 deductible)");
  it.todo("rune damage of 200 G yields payout 100 G (full minus 100 deductible)");
  it.todo("payout rounds down in MHPCO's favor");

  // Claim — special clauses
  it.todo("high enchantment (≥ 8) reimburses 50% of damage, then deductible");
  it.todo("dragon material item is fully reimbursed");
  it.todo("dragon material with high enchantment: 50% rule wins, then deductible");

  // Claim — multiple damages
  it.todo("multiple damages each get their own deductible");

  // Claim — cap
  it.todo("payout capped at twice the insurance sum");
  it.todo("successive claims exhaust remaining cap");

  // Multi-item policy
  it.todo("policy with cursed sword and plain amulet yields 215 G");
  it.todo("policy with two swords has insurance sum 2000 G, cap 4000 G");

  // Errors
  it.todo("unknown item type causes CLI to exit non-zero");
  it.todo("claim with item not in policy causes non-zero exit");
  it.todo("claim with negative damage amount causes non-zero exit");
  it.todo("more damage entries of a type than insured items causes non-zero exit");
});

