const itemSurchargeRate = (item: Item): number =>
  ITEM_SURCHARGE_RATES.reduce((sum, rate) => sum + rate(item), 0);

const itemSurcharges = (items: Item[]): number =>
  items.reduce((sum, item) => sum + basePremiumFor(item) * itemSurchargeRate(item), 0);

const LOYALTY_THRESHOLD_YEARS = 2;
const LOYALTY_DISCOUNT_RATE = 0.2;

const policyDiscountRate = (customer: Customer): number =>
  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? LOYALTY_DISCOUNT_RATE : 0;

const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;

const isNewcomer = (customer: Customer): boolean => customer.yearsWithMHPCO === 0;

const firstInsuranceSurchargeRate = (customer: Customer): number =>
  isNewcomer(customer) ? FIRST_INSURANCE_SURCHARGE_RATE : 0;

const quote = ({ items }: QuoteStep, customer: Customer): QuoteResult => {
  const baseTotal = itemsBaseTotal(items);
  return {
    premium:
      baseTotal * (1 - policyDiscountRate(customer)) +
      baseTotal * firstInsuranceSurchargeRate(customer) +
      itemSurcharges(items) +
      PROCESSING_FEE,
  };
};

export const runScenario = (scenario: Scenario): ScenarioResult => ({
  results: scenario.steps.map((step) =>
    step.op === "quote" ? quote(step, scenario.customer) : { payout: 0, remainingCap: 0 },
  ),
});

