  baseTotal: number,
  customer: Customer,
  isFollowUp: boolean,
): number =>
  baseTotal * (1 - policyDiscountRate(customer) - followUpDiscountRate(isFollowUp)) +
  baseTotal * FIRST_INSURANCE_SURCHARGE_RATE;

