  { items }: QuoteStep,
  customer: Customer,
  isFollowUp: boolean,
): QuoteResult => ({
  premium: Math.ceil(
    policyAdjustedBase(itemsBaseTotal(items), customer, isFollowUp) +
      itemSurcharges(items) +
      PROCESSING_FEE,
