  results: scenario.steps.reduce<StepResult[]>((results, step, index) => {
    const result =
      step.op === "quote"
        ? quote(step, scenario.customer, hasPriorQuote(scenario.steps, index))
        : claim(step, scenario.steps, results);
    return [...results, result];
  }, []),
});

